#!/usr/bin/env bash
# ============================================================================
#  Portfolio Upgrade Script — Afeez Temitope Bello
#  ----------------------------------------------------------------------------
#  Adds:
#    • Glassmorphism + 3D tilt project folders (hover on web, modal on mobile)
#    • Loading screen with name + Klassrun tagline (slow-network message)
#    • Full PWA support (manifest, service worker, offline page, install prompt)
#    • SEO upgrades: TikTok handle fix, Bing tag, expanded sitemap, ProfilePage schema
#    • Performance: code splitting, preconnect, GPU-accelerated transforms
#    • Bug fix: broken useState stub in App.tsx (scroll-to-top button now works)
#
#  Preserves: all 13 projects, descriptions, links, color scheme, JSON-LD
#  Backs up your code before changing anything.
# ============================================================================

set -e  # exit on any error
trap 'echo ""; log "❌ Script failed at line $LINENO. Your backup is intact."; exit 1' ERR

# Colors
GREEN='\033[0;32m'
BLUE='\033[0;34m'
YELLOW='\033[1;33m'
CYAN='\033[0;36m'
BOLD='\033[1m'
NC='\033[0m'

log() { echo -e "${BLUE}[upgrade]${NC} $*"; }
success() { echo -e "${GREEN}[ ✓ ]${NC} $*"; }
warn() { echo -e "${YELLOW}[ ! ]${NC} $*"; }
header() { echo -e "\n${BOLD}${CYAN}━━━ $* ━━━${NC}"; }

# Resolve project directory — defaults to current dir, or pass as $1
PROJECT_DIR="${1:-$(pwd)}"
PROJECT_DIR="$(cd "$PROJECT_DIR" && pwd)"

if [ ! -f "$PROJECT_DIR/package.json" ]; then
  echo -e "${YELLOW}❌ No package.json found in: $PROJECT_DIR${NC}"
  echo "   Run this script from inside your portfolio folder, or pass the path:"
  echo "   bash upgrade-portfolio.sh /path/to/Portfolioo-main"
  exit 1
fi

if ! grep -q '"react"' "$PROJECT_DIR/package.json"; then
  warn "This doesn't look like the React portfolio project. Continuing anyway..."
fi

# ============================================================================
# STEP 1 — Backup
# ============================================================================
header "STEP 1/8  Creating backup"

TIMESTAMP=$(date +%Y%m%d-%H%M%S)
BACKUP_DIR="${PROJECT_DIR}.backup-${TIMESTAMP}"

cp -r "$PROJECT_DIR" "$BACKUP_DIR"
success "Backup created at: $BACKUP_DIR"

# ============================================================================
# STEP 2 — Write all new component files
# ============================================================================
header "STEP 2/8  Writing new component files"

# Write: src/components/Project.tsx
mkdir -p "$(dirname "$PROJECT_DIR/src/components/Project.tsx")"
echo '' | base64 -d > "$PROJECT_DIR/src/components/Project.tsx"
log "  ✓ src/components/Project.tsx"

# Write: src/App.tsx
mkdir -p "$(dirname "$PROJECT_DIR/src/App.tsx")"
echo '' | base64 -d > "$PROJECT_DIR/src/App.tsx"
log "  ✓ src/App.tsx"

# Write: src/components/LoadingScreen.tsx
mkdir -p "$(dirname "$PROJECT_DIR/src/components/LoadingScreen.tsx")"
echo '' | base64 -d > "$PROJECT_DIR/src/components/LoadingScreen.tsx"
log "  ✓ src/components/LoadingScreen.tsx"

# Write: src/components/PWAInstallPrompt.tsx
mkdir -p "$(dirname "$PROJECT_DIR/src/components/PWAInstallPrompt.tsx")"
echo '' | base64 -d > "$PROJECT_DIR/src/components/PWAInstallPrompt.tsx"
log "  ✓ src/components/PWAInstallPrompt.tsx"

# Write: index.html
mkdir -p "$(dirname "$PROJECT_DIR/index.html")"
echo '' | base64 -d > "$PROJECT_DIR/index.html"
log "  ✓ index.html"

# Write: public/sw.js
mkdir -p "$(dirname "$PROJECT_DIR/public/sw.js")"
echo '' | base64 -d > "$PROJECT_DIR/public/sw.js"
log "  ✓ public/sw.js"

# Write: public/manifest.webmanifest
mkdir -p "$(dirname "$PROJECT_DIR/public/manifest.webmanifest")"
echo '' | base64 -d > "$PROJECT_DIR/public/manifest.webmanifest"
log "  ✓ public/manifest.webmanifest"

# Write: public/offline.html
mkdir -p "$(dirname "$PROJECT_DIR/public/offline.html")"
echo '' | base64 -d > "$PROJECT_DIR/public/offline.html"
log "  ✓ public/offline.html"

# Write: public/sitemap.xml
mkdir -p "$(dirname "$PROJECT_DIR/public/sitemap.xml")"
echo '' | base64 -d > "$PROJECT_DIR/public/sitemap.xml"
log "  ✓ public/sitemap.xml"

# Write: public/robots.txt
mkdir -p "$(dirname "$PROJECT_DIR/public/robots.txt")"
echo '' | base64 -d > "$PROJECT_DIR/public/robots.txt"
log "  ✓ public/robots.txt"

# Write: vite.config.ts
mkdir -p "$(dirname "$PROJECT_DIR/vite.config.ts")"
echo '' | base64 -d > "$PROJECT_DIR/vite.config.ts"
log "  ✓ vite.config.ts"


# ============================================================================
# STEP 3 — Append CSS additions to existing index.css
# ============================================================================
header "STEP 3/8  Appending CSS additions (3D perspective + glassmorphism)"

CSS_FILE="$PROJECT_DIR/src/index.css"
CSS_MARKER="ENHANCEMENTS BY UPGRADE SCRIPT"

if grep -q "$CSS_MARKER" "$CSS_FILE" 2>/dev/null; then
  warn "CSS additions already present — skipping append"
else
  echo "" | base64 -d >> "$CSS_FILE"
  success "  ✓ Appended ~30 lines of new CSS to src/index.css"
fi

# ============================================================================
# STEP 4 — Patch Header.tsx (TikTok handle fix)
# ============================================================================
header "STEP 4/8  Fixing TikTok handle in Header.tsx"

HEADER_FILE="$PROJECT_DIR/src/components/Header.tsx"
if grep -q "@tbelzbby2" "$HEADER_FILE" 2>/dev/null; then
  # macOS sed needs '' after -i; GNU sed doesn't. Detect and handle both.
  if [[ "$OSTYPE" == "darwin"* ]]; then
    sed -i '' 's|https://www.tiktok.com/@tbelzbby2|https://www.tiktok.com/@afeez_can_code|g' "$HEADER_FILE"
  else
    sed -i 's|https://www.tiktok.com/@tbelzbby2|https://www.tiktok.com/@afeez_can_code|g' "$HEADER_FILE"
  fi
  success "  ✓ TikTok handle: @tbelzbby2 → @afeez_can_code"
else
  warn "  TikTok handle already correct or not found — skipping"
fi

# ============================================================================
# STEP 5 — Generate PWA icons (192x192 + 512x512)
# ============================================================================
header "STEP 5/8  Generating PWA icons"

ICON_192="$PROJECT_DIR/public/icon-192.png"
ICON_512="$PROJECT_DIR/public/icon-512.png"

if [ -f "$ICON_192" ] && [ -f "$ICON_512" ]; then
  warn "  Icons already exist — keeping existing ones (delete them to regenerate)"
else
  TMP_PY=$(mktemp --suffix=.py)
  echo "" | base64 -d > "$TMP_PY"

  if command -v python3 &> /dev/null; then
    if python3 -c "import PIL" 2>/dev/null; then
      python3 "$TMP_PY" "$PROJECT_DIR/public/" || warn "Icon generation failed — you can add icon-192.png and icon-512.png manually"
    else
      warn "  Python Pillow not installed. Trying to install..."
      pip3 install Pillow --break-system-packages --quiet 2>/dev/null || pip install Pillow --quiet 2>/dev/null || true
      if python3 -c "import PIL" 2>/dev/null; then
        python3 "$TMP_PY" "$PROJECT_DIR/public/"
      else
        warn "  Could not install Pillow. Add icon-192.png and icon-512.png manually."
        warn "  Or run: pip install Pillow && python3 $TMP_PY $PROJECT_DIR/public/"
      fi
    fi
  else
    warn "  Python 3 not found. Add icon-192.png and icon-512.png manually to /public/"
  fi
  rm -f "$TMP_PY"
fi

# ============================================================================
# STEP 6 — Verify dependencies
# ============================================================================
header "STEP 6/8  Verifying dependencies"

cd "$PROJECT_DIR"
if [ -d "node_modules" ]; then
  success "  node_modules present — skipping install"
else
  log "  Installing dependencies (one-time, may take 1-2 min)..."
  npm install --silent
  success "  Dependencies installed"
fi

# ============================================================================
# STEP 7 — Type-check
# ============================================================================
header "STEP 7/8  Type-checking new code"

if npx tsc --noEmit 2>&1 | tee /tmp/tsc-output.log | head -20; then
  if [ -s /tmp/tsc-output.log ]; then
    warn "  TypeScript reported issues above — review them, but build may still work"
  else
    success "  Zero TypeScript errors"
  fi
else
  warn "  Type-check had warnings — review the output above"
fi

# ============================================================================
# STEP 8 — Production build smoke test
# ============================================================================
header "STEP 8/8  Running production build (smoke test)"

if npx vite build 2>&1 | tail -10; then
  success "  Production build succeeded — site is ready to deploy"
else
  warn "  Build failed — check the errors above. Your backup is at: $BACKUP_DIR"
  exit 1
fi

# ============================================================================
# DONE — Summary
# ============================================================================
echo ""
echo -e "${BOLD}${GREEN}╔════════════════════════════════════════════════════════════╗${NC}"
echo -e "${BOLD}${GREEN}║              UPGRADE COMPLETE                             ║${NC}"
echo -e "${BOLD}${GREEN}╚════════════════════════════════════════════════════════════╝${NC}"
echo ""
echo -e "${BOLD}What changed:${NC}"
echo ""
echo -e "  ${CYAN}UI / Animations${NC}"
echo "    • src/components/Project.tsx       — 3D tilt folder cards + mobile modal"
echo "    • src/components/LoadingScreen.tsx — splash with name + Klassrun tagline"
echo "    • src/components/PWAInstallPrompt.tsx — appears after 30s on site"
echo "    • src/index.css                    — glassmorphism + perspective styles"
echo ""
echo -e "  ${CYAN}PWA / Offline${NC}"
echo "    • public/manifest.webmanifest      — installable app manifest"
echo "    • public/sw.js                     — service worker (network-first HTML, SWR images)"
echo "    • public/offline.html              — branded offline fallback page"
echo "    • public/icon-192.png + icon-512.png — app icons (AB on blue/purple gradient)"
echo ""
echo -e "  ${CYAN}SEO / Discoverability${NC}"
echo "    • index.html                       — Bing meta tag, ProfilePage schema, theme-color"
echo "    • src/components/Header.tsx        — TikTok handle fixed (@tbelzbby2 → @afeez_can_code)"
echo "    • public/sitemap.xml               — image sitemap, section anchors"
echo "    • public/robots.txt                — explicit allow for Google/Bing/Yahoo/DuckDuckGo"
echo ""
echo -e "  ${CYAN}Performance / Bug fixes${NC}"
echo "    • src/App.tsx                      — fixed broken useState stub (scroll-to-top works now)"
echo "    • vite.config.ts                   — manual chunks (react/motion/icons split)"
echo "    • index.html                       — preconnect to Cloudinary, dns-prefetch TikTok"
echo ""
echo -e "${BOLD}${YELLOW}MANUAL STEPS REMAINING:${NC}"
echo ""
echo -e "  ${BOLD}1. Bing Webmaster Tools${NC} (3 min, biggest discoverability win)"
echo "     → Visit https://www.bing.com/webmasters"
echo "     → Add site: afeeztemitope.com"
echo "     → Choose 'HTML Meta Tag' verification"
echo "     → Replace YOUR_BING_VERIFICATION_CODE_HERE in index.html with the code Bing gives you"
echo "     → Click Verify — Bing now indexes you (powers DuckDuckGo + Yahoo + ChatGPT search)"
echo ""
echo -e "  ${BOLD}2. Update your TikTok bio${NC} (2 min, makes Google connect the dots)"
echo "     → Open https://www.tiktok.com/@afeez_can_code"
echo "     → Edit profile → set bio link to: https://afeeztemitope.com"
echo "     → Add 'Afeez Temitope Bello' to display name (not just @afeez_can_code)"
echo "     → This bidirectional link is exactly what Google's E-E-A-T algorithm looks for"
echo ""
echo -e "  ${BOLD}3. Re-submit sitemap to Google${NC}"
echo "     → Visit https://search.google.com/search-console"
echo "     → Sitemaps → submit: https://afeeztemitope.com/sitemap.xml"
echo "     → Re-indexing usually takes 2-7 days"
echo ""
echo -e "  ${BOLD}4. Test the PWA install${NC}"
echo "     → Deploy your site"
echo "     → Open in Chrome on Android: 'Add to Home Screen' should appear"
echo "     → On desktop Chrome: install icon appears in URL bar"
echo ""
echo -e "${BOLD}TIKTOK-IN-GOOGLE FIX EXPLAINED:${NC}"
echo ""
echo "  Google decides which social profiles to show in search results based on"
echo "  THREE consistent signals all pointing at the same person:"
echo ""
echo "    1. JSON-LD sameAs in your site         ← already had this ✓"
echo "    2. Visible link from your site to TikTok ← was wrong handle, NOW FIXED ✓"
echo "    3. Link from TikTok bio back to site   ← do this manually (step 2 above)"
echo ""
echo "  Once all three match, your TikTok will start appearing in Google results"
echo "  for searches like 'Afeez Temitope Bello' or 'afeez can code' within ~7-14 days."
echo ""
echo -e "${BOLD}TO DEPLOY:${NC}"
echo ""
echo "  npm run dev          # local preview"
echo "  npm run build        # production build"
echo "  # then deploy /dist to Vercel/Netlify as usual"
echo ""
echo -e "${BOLD}TO ROLLBACK (if anything looks off):${NC}"
echo ""
echo "  rm -rf $PROJECT_DIR"
echo "  mv $BACKUP_DIR $PROJECT_DIR"
echo ""
echo -e "${GREEN}Backup location:${NC} $BACKUP_DIR"
echo ""
